import{_ as a,o as l,c as i,ae as t}from"./chunks/framework.Czhw_PXq.js";const u=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"guide/architecture.md","filePath":"guide/architecture.md"}'),r={name:"guide/architecture.md"};function o(n,e,s,c,d,h){return l(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><p><code>shardd</code> splits the system into two planes.</p><h2 id="private-state-plane" tabindex="-1">Private state plane <a class="header-anchor" href="#private-state-plane" aria-label="Permalink to &quot;Private state plane&quot;">​</a></h2><ul><li>full nodes</li><li>local Postgres per full node</li><li>private libp2p mesh</li><li>replication, sync, and convergence</li></ul><p>These nodes are correctness-critical and should stay private.</p><h2 id="public-edge-plane" tabindex="-1">Public edge plane <a class="header-anchor" href="#public-edge-plane" aria-label="Permalink to &quot;Public edge plane&quot;">​</a></h2><ul><li>regional edge gateways</li><li>public HTTPS</li><li>developer API key auth</li><li>public edge discovery</li><li>full-node selection based on live mesh health</li></ul><p>The edge gateway is not a dumb proxy. It participates in the private mesh enough to maintain a live routing view, but it holds no shard state of its own.</p><h2 id="why-this-is-cleaner" tabindex="-1">Why this is cleaner <a class="header-anchor" href="#why-this-is-cleaner" aria-label="Permalink to &quot;Why this is cleaner&quot;">​</a></h2><ul><li>public developers do not need libp2p credentials</li><li>full nodes do not become an internet-facing auth surface</li><li>client tooling stays simple: HTTPS plus a bearer key</li><li>routing decisions use live mesh state, not just DNS</li></ul><h2 id="deployment-shape" tabindex="-1">Deployment shape <a class="header-anchor" href="#deployment-shape" aria-label="Permalink to &quot;Deployment shape&quot;">​</a></h2><p>Typical production layout:</p><ul><li>a few full-node regions</li><li>more public edge regions than full-node regions</li><li>one separate control-plane/dashboard host</li></ul><p>Typical dev layout:</p><ul><li>3 full nodes</li><li>3 public edges</li><li>1 dashboard host</li></ul>',15)])])}const b=a(r,[["render",o]]);export{u as __pageData,b as default};
